# List all users with high or medium user risk
Connect-MgGraph -Scopes 'IdentityRiskyUser.Read.All', 'IdentityRiskyUser.ReadWrite.All'

$riskyUsers = Get-MgRiskyUser -Filter "riskLevel eq 'high' or riskLevel eq 'medium'" -Top 100
foreach ($u in $riskyUsers) {
    [PSCustomObject]@{
        UPN          = $u.UserPrincipalName
        RiskLevel    = $u.RiskLevel
        RiskState    = $u.RiskState
        RiskDetail   = $u.RiskDetail
        LastUpdated  = $u.RiskLastUpdatedDateTime
    }
} | Format-Table -AutoSize

# Get risk history for a specific user (shows each detection event over time)
$history = Get-MgRiskyUserHistory -RiskyUserId '<object-id>'
foreach ($h in $history) {
    Write-Host "$($h.ActivityDateTime): $($h.RiskState) — Types: $($h.RiskEventTypes -join ', ')"
}

# Get a single user's current risk level by UPN
$user = Get-MgRiskyUser -Filter "userPrincipalName eq 'alice@contoso.com'"
Write-Host "$($user.UserPrincipalName): $($user.RiskLevel) [$($user.RiskState)]"

# CA policy: require MFA + SSPR for high user risk
# When user completes SSPR, Identity Protection auto-resets user risk to 'remediated'
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: High User Risk - Password Change'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('all') }
        UserRiskLevels = @('high')
    }
    GrantControls = @{
        Operator = 'AND'
        BuiltInControls = @('mfa', 'passwordChange')
    }
}

# SSPR must be enabled and configured for this policy to work.
# If SSPR is not enabled, users hit this policy and cannot satisfy it — they are locked out.
# Verify SSPR state before enabling:
Get-MgPolicyAuthorizationPolicy | Select-Object AllowedToResetPassword

# Guest users and external identities in risky user reports
# Guests authenticate in the resource tenant but have limited SSPR options

# Find all risky users who are guests
Connect-MgGraph -Scopes 'IdentityRiskyUser.Read.All', 'User.Read.All'

$riskyUsers = Get-MgRiskyUser -Filter "riskLevel eq 'high' or riskLevel eq 'medium'"
$riskyGuests = foreach ($u in $riskyUsers) {
    $mgUser = Get-MgUser -UserId $u.Id -Property UserType, UserPrincipalName
    if ($mgUser.UserType -eq 'Guest') {
        [PSCustomObject]@{
            UPN = $u.UserPrincipalName
            RiskLevel = $u.RiskLevel
            UserType = 'Guest'
        }
    }
}
$riskyGuests | Format-Table

# For guest users, SSPR in the resource tenant is not available.
# Options:
#   1. Dismiss the risk if sign-in was legitimate (requires investigation)
#   2. Remove guest access (revoke invitation, delete guest object)
#   3. Contact the guest's home tenant admin to investigate their account
#   4. Use CA policy to block guests with elevated user risk

# CA policy: block guests with high user risk
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = "CA: Block Risky Guests"
    State = "enabled"
    Conditions = @{
        Users = @{
            IncludeGuestsOrExternalUsers = @{
                GuestOrExternalUserTypes = "internalGuest,b2bCollaborationGuest,b2bCollaborationMember"
                ExternalTenants = @{ MembershipKind = "all" }
            }
        }
        Applications = @{ IncludeApplications = @("all") }
        UserRiskLevels = @("high")
    }
    GrantControls = @{
        Operator = "OR"
        BuiltInControls = @("block")
    }
}
